import json
from langchain.tools import tool
from langchain_core.documents import Document

@tool
def search_with_metadata(query: str) -> str:
    """Search documents and return structured results with source and relevance score.
    Input: a search query string.
    Output: JSON list of {source, score, excerpt} for up to 5 matches."""
    docs_and_scores: list[tuple[Document, float]] = vector_store.similarity_search_with_score(
        query, k=5
    )
    results = [
        {
            "source": d.metadata.get("source", "unknown"),
            "page": d.metadata.get("page", None),
            "score": round(float(score), 3),
            "excerpt": d.page_content[:300],
        }
        for d, score in docs_and_scores
    ]
    return json.dumps(results, ensure_ascii=False)

from dataclasses import dataclass, field
from typing import Any
from langchain.tools import tool
import json

@dataclass
class CitationTracker:
    citations: list[dict] = field(default_factory=list)

    def record(self, query: str, docs: list) -> str:
        """Serialize docs, record citations, return formatted string for LLM."""
        lines = []
        for d in docs:
            src = d.metadata.get("source", "unknown")
            page = d.metadata.get("page", "?")
            cite_id = len(self.citations) + 1
            self.citations.append({
                "id": cite_id,
                "source": src,
                "page": page,
                "query": query,
                "excerpt": d.page_content[:200],
            })
            lines.append(f"[{cite_id}] [{src} p.{page}] {d.page_content}")
        return "\n\n".join(lines)

tracker = CitationTracker()

def make_search_tool(tracker: CitationTracker):
    @tool
    def search_documents(query: str) -> str:
        """Search company documents. Returns excerpts with citation IDs.
        Reference citations in your answer as [1], [2], etc."""
        docs = vector_store.similarity_search(query, k=5)
        return tracker.record(query, docs)
    return search_documents

